Rules.InvariantScript:
If(Confirm("Delete this CR? This cannot be undone."),
  Remove(CRRequests, gblDetailCR);
  Navigate('View CRs Screen', ScreenTransition.None);
  Notify("CR deleted.", NotificationType.Warning)
)

Patch(CRRequests, gblDetailCR, {CRStatus: {Value: "In Assessment"}});
If(IsEmpty(Errors(CRRequests)),
  Set(gblDetailCR, LookUp(CRRequests, CRNumber = gblDetailCR.CRNumber));
  Notify(gblDetailCR.CRNumber & " accepted and distributed for assessment.", NotificationType.Success),
  Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)

Patch(CRRequests, gblDetailCR, {CRStatus: {Value: "Submitted"}});
If(IsEmpty(Errors(CRRequests)),
  Set(gblDetailCR, LookUp(CRRequests, CRNumber = gblDetailCR.CRNumber));
  Notify(gblDetailCR.CRNumber & " returned to owner.", NotificationType.Warning),
  Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)

If(CountRows(Filter(CRStakeholderReviews,
    CRNumber = gblDetailCR.CRNumber, RAGStatus.Value = "Pale Blue")) > 0,
  Notify("Cannot proceed — " &
    Text(CountRows(Filter(CRStakeholderReviews, CRNumber = gblDetailCR.CRNumber, RAGStatus.Value = "Pale Blue"))) &
    " stakeholder group(s) are still Pale Blue. All assessments must be complete before SG distribution.",
    NotificationType.Error),
  Patch(CRRequests, gblDetailCR, {CRStatus: {Value: "Pre-SG Distribution"}});
  If(IsEmpty(Errors(CRRequests)),
    Set(gblDetailCR, LookUp(CRRequests, CRNumber = gblDetailCR.CRNumber));
    Notify("CR marked ready for Pre-SG Distribution.", NotificationType.Success),
    Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
  )
)

Patch(CRRequests, gblDetailCR, {CRStatus: {Value: "Closed"}, ClosedDate: Today()});
If(IsEmpty(Errors(CRRequests)),
  Set(gblDetailCR, LookUp(CRRequests, CRNumber = gblDetailCR.CRNumber));
  Notify(gblDetailCR.CRNumber & " closed.", NotificationType.Success),
  Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)
